import 'package:flutter/material.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_riverpod/flutter_riverpod.dart';
import 'package:quiz_app/core/navigation/app_router.dart';
import 'package:quiz_app/core/navigation/route_constants.dart';
import 'package:quiz_app/core/navigation/navigation_utils.dart';
import 'package:quiz_app/core/navigation/auth_guard.dart';
import 'package:quiz_app/main.dart';
import 'test_config.dart';
import 'helpers/test_utilities.dart';

/// Comprehensive Navigation System Tests\n/// Tests the complete navigation infrastructure including routing, guards, and utilities\nvoid main() {\n  testGroup('Navigation System Integration Tests', TestCategory.integration, () {\n    widgetTestCase('should initialize app with correct router configuration',\n        TestCategory.integration, (WidgetTester tester) async {\n      // ARRANGE & ACT\n      await tester.pumpWidget(const ProviderScope(child: QuizApp()));\n      await tester.pumpAndSettle();\n\n      // ASSERT - Should start at splash screen\n      expect(find.text('Quiz App'), findsOneWidget);\n    });\n\n    widgetTestCase('should provide router through Riverpod correctly',\n        TestCategory.integration, (WidgetTester tester) async {\n      // ARRANGE & ACT\n      await tester.pumpWidget(\n        ProviderScope(\n          child: Consumer(\n            builder: (context, ref, child) {\n              final router = ref.watch(routerProvider);\n              expect(router, isNotNull);\n              expect(router.routerDelegate, isNotNull);\n              expect(router.routeInformationParser, isNotNull);\n\n              return MaterialApp.router(routerConfig: router);\n            },\n          ),\n        ),\n      );\n\n      // ASSERT\n      await tester.pumpAndSettle();\n    });\n  });\n\n  testGroup('Route Constants Validation', TestCategory.unit, () {\n    testCase('should have all required route constants defined',\n        TestCategory.unit, () {\n      // ASSERT - Core routes\n      expect(RouteConstants.root, equals('/'));\n      expect(RouteConstants.splash, equals('/splash'));\n      expect(RouteConstants.home, equals('/home'));\n      \n      // Auth routes\n      expect(RouteConstants.login, equals('/login'));\n      expect(RouteConstants.register, equals('/register'));\n      expect(RouteConstants.forgotPassword, equals('/forgot-password'));\n      expect(RouteConstants.profile, equals('/profile'));\n      \n      // Dashboard\n      expect(RouteConstants.dashboard, equals('/dashboard'));\n      \n      // Game routes\n      expect(RouteConstants.gameJoin, equals('/game/join'));\n      expect(RouteConstants.gameHost, equals('/game/host'));\n      \n      // Quiz routes\n      expect(RouteConstants.quizCreation, equals('/quiz-creation'));\n      \n      // Leaderboard\n      expect(RouteConstants.leaderboard, equals('/leaderboard'));\n      \n      // Settings\n      expect(RouteConstants.settings, equals('/settings'));\n      expect(RouteConstants.about, equals('/about'));\n      expect(RouteConstants.help, equals('/help'));\n      \n      // Error routes\n      expect(RouteConstants.notFound, equals('/404'));\n      expect(RouteConstants.error, equals('/error'));\n    });\n\n    testCase('should generate dynamic route paths correctly',\n        TestCategory.unit, () {\n      // ASSERT - Dynamic quiz routes\n      expect(\n        RouteConstants.quizDetailsPath('test123'),\n        equals('/quiz/test123'),\n      );\n      expect(\n        RouteConstants.quizEditPath('test123'),\n        equals('/quiz/test123/edit'),\n      );\n      \n      // Dynamic game routes\n      expect(\n        RouteConstants.gameSessionPath('game456'),\n        equals('/game/game456'),\n      );\n      expect(\n        RouteConstants.gameWaitingPath('game456'),\n        equals('/game/game456/waiting'),\n      );\n      expect(\n        RouteConstants.gameQuestionPath('game456', 2),\n        equals('/game/game456/question/2'),\n      );\n      expect(\n        RouteConstants.gameResultsPath('game456'),\n        equals('/game/game456/results'),\n      );\n      \n      // Dynamic leaderboard routes\n      expect(\n        RouteConstants.leaderboardSessionPath('session789'),\n        equals('/leaderboard/session/session789'),\n      );\n    });\n  });\n\n  testGroup('Navigation Utils Functionality', TestCategory.unit, () {\n    testCase('should generate shareable URLs correctly', TestCategory.unit, () {\n      // ARRANGE & ACT\n      final quizShareUrl = NavigationUtils.generateQuizShareUrl('quiz123');\n      final gameJoinUrl = NavigationUtils.generateGameJoinUrl('123456');\n      final leaderboardUrl = NavigationUtils.generateLeaderboardShareUrl('session123');\n\n      // ASSERT\n      expect(quizShareUrl, contains('/quiz/quiz123'));\n      expect(quizShareUrl, startsWith('https://'));\n      \n      expect(gameJoinUrl, contains('/game/join?pin=123456'));\n      expect(gameJoinUrl, startsWith('https://'));\n      \n      expect(leaderboardUrl, contains('/leaderboard/session/session123'));\n      expect(leaderboardUrl, startsWith('https://'));\n    });\n\n    testCase('should validate route parameters correctly', TestCategory.unit,\n        () {\n      // ASSERT - Quiz ID validation\n      expect(NavigationUtils.isValidQuizId('quiz123456'), isTrue);\n      expect(NavigationUtils.isValidQuizId(''), isFalse);\n      expect(NavigationUtils.isValidQuizId(null), isFalse);\n      expect(NavigationUtils.isValidQuizId('short'), isFalse);\n\n      // Session ID validation\n      expect(NavigationUtils.isValidSessionId('session123456'), isTrue);\n      expect(NavigationUtils.isValidSessionId(''), isFalse);\n      expect(NavigationUtils.isValidSessionId(null), isFalse);\n      \n      // Question index validation\n      expect(NavigationUtils.isValidQuestionIndex(0), isTrue);\n      expect(NavigationUtils.isValidQuestionIndex(5), isTrue);\n      expect(NavigationUtils.isValidQuestionIndex(-1), isFalse);\n      expect(NavigationUtils.isValidQuestionIndex(null), isFalse);\n    });\n\n    testCase('should classify routes correctly', TestCategory.unit, () {\n      // ASSERT - Auth route classification\n      expect(NavigationUtils.isAuthRoute('/login'), isTrue);\n      expect(NavigationUtils.isAuthRoute('/register'), isTrue);\n      expect(NavigationUtils.isAuthRoute('/forgot-password'), isTrue);\n      expect(NavigationUtils.isAuthRoute('/home'), isFalse);\n\n      // Game route classification\n      expect(NavigationUtils.isGameRoute('/game/join'), isTrue);\n      expect(NavigationUtils.isGameRoute('/game/session123'), isTrue);\n      expect(NavigationUtils.isGameRoute('/game/session123/waiting'), isTrue);\n      expect(NavigationUtils.isGameRoute('/home'), isFalse);\n      \n      // Quiz route classification\n      expect(NavigationUtils.isQuizRoute('/quiz/123'), isTrue);\n      expect(NavigationUtils.isQuizRoute('/quiz-creation'), isTrue);\n      expect(NavigationUtils.isQuizRoute('/quiz-creation/form'), isTrue);\n      expect(NavigationUtils.isQuizRoute('/home'), isFalse);\n      \n      // Leaderboard route classification\n      expect(NavigationUtils.isLeaderboardRoute('/leaderboard'), isTrue);\n      expect(NavigationUtils.isLeaderboardRoute('/leaderboard/global'), isTrue);\n      expect(NavigationUtils.isLeaderboardRoute('/home'), isFalse);\n    });\n\n    testCase('should extract game PIN from URLs correctly', TestCategory.unit,\n        () {\n      // ASSERT - Valid URLs with query parameters\n      expect(\n        NavigationUtils.extractGamePinFromUrl(\n          'https://example.com/game/join?pin=123456',\n        ),\n        equals('123456'),\n      );\n      \n      // Valid URLs with PIN in path\n      expect(\n        NavigationUtils.extractGamePinFromUrl(\n          'https://example.com/game/123456',\n        ),\n        equals('123456'),\n      );\n      \n      // Invalid URLs\n      expect(\n        NavigationUtils.extractGamePinFromUrl('invalid-url'),\n        isNull,\n      );\n      expect(\n        NavigationUtils.extractGamePinFromUrl(\n          'https://example.com/game/join?pin=12345',\n        ),\n        isNull,\n      ); // PIN too short\n    });\n  });\n\n  testGroup('Route Guard System', TestCategory.unit, () {\n    testCase('should have guards configured for protected routes',\n        TestCategory.unit, () {\n      // ASSERT - Auth routes should have GuestGuard\n      final loginGuards = AuthGuardRegistry.getGuards(RouteConstants.login);\n      expect(loginGuards, isNotEmpty);\n      expect(loginGuards.first, isA<GuestGuard>());\n      \n      final registerGuards = AuthGuardRegistry.getGuards(RouteConstants.register);\n      expect(registerGuards, isNotEmpty);\n      expect(registerGuards.first, isA<GuestGuard>());\n\n      // Protected routes should have AuthGuard\n      final dashboardGuards =\n          AuthGuardRegistry.getGuards(RouteConstants.dashboard);\n      expect(dashboardGuards, isNotEmpty);\n      expect(dashboardGuards.first, isA<AuthGuard>());\n      \n      final profileGuards = AuthGuardRegistry.getGuards(RouteConstants.profile);\n      expect(profileGuards, isNotEmpty);\n      expect(profileGuards.first, isA<AuthGuard>());\n    });\n\n    testCase('should return empty guards for unprotected routes',\n        TestCategory.unit, () {\n      // ASSERT - Public routes should have no guards\n      final homeGuards = AuthGuardRegistry.getGuards(RouteConstants.home);\n      expect(homeGuards, isEmpty);\n      \n      final aboutGuards = AuthGuardRegistry.getGuards(RouteConstants.about);\n      expect(aboutGuards, isEmpty);\n      \n      final helpGuards = AuthGuardRegistry.getGuards(RouteConstants.help);\n      expect(helpGuards, isEmpty);\n    });\n\n    testCase('should match parametrized routes for guards correctly',\n        TestCategory.unit, () {\n      // ASSERT - Game session routes should have SessionGuard\n      final sessionGuards =\n          AuthGuardRegistry.getGuards('/game/test-session-123');\n      expect(sessionGuards, isNotEmpty);\n      expect(sessionGuards.first, isA<SessionGuard>());\n      \n      // Quiz edit routes should have multiple guards\n      final quizEditGuards =\n          AuthGuardRegistry.getGuards('/quiz/test-quiz-123/edit');\n      expect(quizEditGuards, isNotEmpty);\n      expect(quizEditGuards, hasLength(2)); // AuthGuard + QuizOwnershipGuard\n    });\n\n    testCase('should identify protected routes correctly', TestCategory.unit,\n        () {\n      // ASSERT - Protected routes\n      expect(AuthGuardRegistry.isProtected(RouteConstants.login), isTrue);\n      expect(AuthGuardRegistry.isProtected(RouteConstants.dashboard), isTrue);\n      expect(AuthGuardRegistry.isProtected(RouteConstants.profile), isTrue);\n\n      // Unprotected routes\n      expect(AuthGuardRegistry.isProtected(RouteConstants.home), isFalse);\n      expect(AuthGuardRegistry.isProtected(RouteConstants.about), isFalse);\n    });\n  });\n\n  testGroup('App Router Helper Functions', TestCategory.unit, () {\n    testCase('should provide navigation context correctly', TestCategory.unit,\n        () {\n      // ARRANGE & ACT\n      final context = AppRouterHelper.getCurrentContext();\n\n      // ASSERT\n      expect(context, isA<NavigationContext>());\n      expect(context.route, isA<String>());\n      expect(context.isGameRoute, isA<bool>());\n      expect(context.isAuthRoute, isA<bool>());\n      expect(context.isQuizRoute, isA<bool>());\n      expect(context.breadcrumbs, isA<List<String>>());\n    });\n\n    testCase('should handle deep link processing', TestCategory.unit, () async {\n      // ARRANGE & ACT\n      final validResult = await AppRouterHelper.handleGameJoinDeepLink(\n        'https://example.com/game/join?pin=123456',\n      );\n      final invalidResult = await AppRouterHelper.handleGameJoinDeepLink(\n        'https://example.com/invalid',\n      );\n\n      // ASSERT\n      expect(validResult, isTrue);\n      expect(invalidResult, isFalse);\n    });\n\n    testCase('should generate share links correctly', TestCategory.unit, () {\n      // ARRANGE & ACT\n      final quizLink = AppRouterHelper.generateQuizShareLink('quiz123');\n      final gameLink = AppRouterHelper.generateGameJoinLink('123456');\n\n      // ASSERT\n      expect(quizLink, contains('quiz123'));\n      expect(gameLink, contains('123456'));\n    });\n  });\n\n  testGroup('Router Analytics', TestCategory.unit, () {\n    setUp(() {\n      RouterAnalytics.clearAnalytics();\n    });\n\n    testCase('should track navigation events correctly', TestCategory.unit, () {\n      // ARRANGE\n      const testRoute = '/test-route';\n\n      // ACT\n      RouterAnalytics.trackNavigation(testRoute);\n\n      // ASSERT\n      final history = RouterAnalytics.navigationHistory;\n      expect(history, contains(testRoute));\n      expect(RouterAnalytics.routeVisitCounts[testRoute], equals(1));\n      expect(RouterAnalytics.recentlyVisited[testRoute], isA<DateTime>());\n    });\n\n    testCase('should limit navigation history size', TestCategory.unit, () {\n      // ARRANGE & ACT - Add more than 50 routes\n      for (int i = 0; i < 60; i++) {\n        RouterAnalytics.trackNavigation('/route-$i');\n      }\n\n      // ASSERT\n      final history = RouterAnalytics.navigationHistory;\n      expect(history.length, equals(50));\n      expect(history.first, equals('/route-10')); // First 10 removed\n      expect(history.last, equals('/route-59'));\n    });\n\n    testCase('should track route visit counts', TestCategory.unit, () {\n      // ARRANGE\n      const testRoute = '/popular-route';\n\n      // ACT\n      for (int i = 0; i < 5; i++) {\n        RouterAnalytics.trackNavigation(testRoute);\n      }\n\n      // ASSERT\n      expect(RouterAnalytics.routeVisitCounts[testRoute], equals(5));\n    });\n\n    testCase('should clear analytics data', TestCategory.unit, () {\n      // ARRANGE\n      RouterAnalytics.trackNavigation('/test-route');\n      expect(RouterAnalytics.navigationHistory, isNotEmpty);\n\n      // ACT\n      RouterAnalytics.clearAnalytics();\n\n      // ASSERT\n      expect(RouterAnalytics.navigationHistory, isEmpty);\n      expect(RouterAnalytics.routeVisitCounts, isEmpty);\n      expect(RouterAnalytics.recentlyVisited, isEmpty);\n    });\n  });\n\n  testGroup('Navigation System Performance', TestCategory.performance, () {\n    widgetTestCase('should handle rapid route changes efficiently',\n        TestCategory.performance, (WidgetTester tester) async {\n      // ARRANGE\n      await tester.pumpWidget(\n        ProviderScope(\n          child: MaterialApp.router(routerConfig: AppRouter.router),\n        ),\n      );\n      await tester.pumpAndSettle();\n\n      final stopwatch = Stopwatch()..start();\n\n      // ACT - Perform rapid navigation\n      final routes = [\n        RouteConstants.home,\n        RouteConstants.about,\n        RouteConstants.help,\n        RouteConstants.gameJoin,\n        RouteConstants.leaderboard,\n      ];\n\n      for (final route in routes) {\n        AppRouter.go(route);\n        await tester.pump();\n      }\n\n      await tester.pumpAndSettle();\n      stopwatch.stop();\n\n      // ASSERT\n      expect(\n        stopwatch.elapsed,\n        lessThan(const Duration(seconds: 2)),\n        reason: 'Rapid navigation should be performant',\n      );\n    });\n\n    widgetTestCase('should handle navigation stack efficiently',\n        TestCategory.performance, (WidgetTester tester) async {\n      // ARRANGE\n      await tester.pumpWidget(\n        ProviderScope(\n          child: MaterialApp.router(routerConfig: AppRouter.router),\n        ),\n      );\n      await tester.pumpAndSettle();\n\n      // ACT - Build navigation stack\n      for (int i = 0; i < 5; i++) {\n        AppRouter.push(RouteConstants.about);\n        await tester.pump();\n      }\n\n      await tester.pumpAndSettle();\n\n      // ASSERT - Should handle stack without performance issues\n      expect(find.text('About'), findsOneWidget);\n\n      // Clear stack\n      AppRouter.clearAndGoTo(RouteConstants.home);\n      await tester.pumpAndSettle();\n    });\n  });\n\n  testGroup('Navigation Error Handling', TestCategory.integration, () {\n    widgetTestCase('should handle invalid routes gracefully',\n        TestCategory.integration, (WidgetTester tester) async {\n      // ARRANGE\n      await tester.pumpWidget(\n        ProviderScope(\n          child: MaterialApp.router(routerConfig: AppRouter.router),\n        ),\n      );\n      await tester.pumpAndSettle();\n\n      // ACT - Navigate to invalid route\n      AppRouter.go('/non-existent-route');\n      await tester.pumpAndSettle();\n\n      // ASSERT - Should show error page or handle gracefully\n      // The exact behavior depends on router error handling configuration\n      expect(\n        find.textContaining('Error'),\n        findsAtLeastNWidgets(0), // May or may not show error depending on implementation\n      );\n    });\n\n    testCase('should handle navigation recovery', TestCategory.unit, () {\n      // ARRANGE & ACT & ASSERT\n      expect(\n        () => NavigationUtils.recoverFromNavigationError(\n          MockBuildContext(),\n        ),\n        returnsNormally,\n      );\n    });\n  });\n\n  testGroup('Platform Integration', TestCategory.integration, () {\n    widgetTestCase('should work correctly on all platforms',\n        TestCategory.integration, (WidgetTester tester) async {\n      // ARRANGE\n      await tester.pumpWidget(\n        ProviderScope(\n          child: MaterialApp.router(routerConfig: AppRouter.router),\n        ),\n      );\n      await tester.pumpAndSettle();\n\n      // ACT - Test platform-specific navigation features\n      final routes = [\n        RouteConstants.home,\n        RouteConstants.about,\n        RouteConstants.gameJoin,\n      ];\n\n      // Test navigation on current platform\n      for (final route in routes) {\n        AppRouter.go(route);\n        await tester.pumpAndSettle();\n        \n        // Should not show error\n        expect(find.textContaining('Navigation Error'), findsNothing);\n      }\n    });\n  });\n}\n\n/// Mock BuildContext for testing\nclass MockBuildContext extends Mock implements BuildContext {}
